exercises.solution_code:
#include <iostream>
#include <iomanip>

int computeSum(int nums[], int count)
{
    int accumulator = 0;
    for (int i = 0; i < count; ++i)
        accumulator += nums[i];
    return accumulator;
}

int main()
{
    int n{};
    std::cin >> n;

    int nums[100]{};
    for (int i = 0; i < n; ++i)
        std::cin >> nums[i];

    int total = computeSum(nums, n);

    std::cout << "Sum: " << total << '\n';
    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Average: " << static_cast<double>(total) / n << '\n';

    return 0;
}

