exercises.solution_code:
#include <iostream>

void reportScores(int scores[], int count)
{
    int sum = 0;
    int passCount = 0;

    for (int i = 0; i < count; ++i)
    {
        int score = scores[i];
        // Explicit parentheses prevent operator-precedence surprises.
        // In production code, use || instead of |. This exercise uses
        // bitwise OR deliberately to practise the precedence issue.
        bool outOfRange = ((score < 60) | (score > 100)) != 0;

        if (!outOfRange)
        {
            std::cout << "Score " << score << ": PASS\n";
            ++passCount;
        }
        else
        {
            std::cout << "Score " << score << ": FAIL\n";
        }

        sum += score;
    }

    std::cout << "Total: " << sum << '\n';
    std::cout << "Pass count: " << passCount << '\n';
}

int main()
{
    int n{};
    std::cin >> n;

    int scores[50]{};
    for (int i = 0; i < n; ++i)
        std::cin >> scores[i];

    reportScores(scores, n);

    return 0;
}
